INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (1082, 88223, 5, 379, '烟花随想', '午夜十二点，钟声敲响，举国观腾，看窗外，满空烟花绽放，轰隆隆似春雷翻滚，响彻云霄，震破一冬的严寒，那是春的使者，将春的气息撒遍人间！凝眸夜空，不觉双眼迷蒙，思绪万千……
<br>    人生便如烟花，蕴籍了多少力量，历经了多少痛苦，就在此刻，一声长啸，划破长空，那是力的展示，生的宣言，生命在此刻有了新的意义！升腾啊！升腾！不愿预想绽放的痛苦，憋足劲，往上冲！看见天空中那最高最耀眼的明星了吗？那是我绽放的地方！无边的黑暗，熄不了我绽放的热情，沉闷的大气压不垮我瘦弱的身躯！“瞧，下面的风景多美！”，“你升腾的轨迹如慧尾扫过天际，快看看这瞬间的异彩”不！我不能回头，我不想留恋过程，是烟花便注定要绽放，我要用燃烧实现自身的价值，用炫丽耀眼的光芒诠释我的人生！也许有人要笑我是痴儿，不解荣枯事，也许绽放就意味着消亡，是！多少秦宫汉阙，都做了衰草牛羊野，纵荒坟，横断碑，不辩龙蛇。然！多少风流韵事，历经了历史风霜雪，涤浊评，竖口碑，长留人间！对于我，选择了便意味着义无反顾！
<br>    不再回头，我要在夜空中绽放，我将与黎明共舞！穷，气不短，达，志不改！', '午夜十二点，钟声敲响，举国观腾，看窗外，满空烟花绽放，轰隆隆似春雷翻滚，响彻云霄，震破一冬的严寒，那是春的使者，将春的气息撒遍人间！凝眸夜空，不觉双眼迷蒙，思绪万千……

人生便如烟花，蕴籍了多少力量，历经了多少痛苦，就在此刻，一声长啸，划破长空，那是力的展示，生的宣言，生命在此刻有了新的意义！升腾啊！升腾！不愿预想绽放的痛苦，憋足劲，往上冲！看见天空中那最高最耀眼的明星了吗？那是我绽放的地方！无边的黑暗，熄不了我绽放的热情，沉闷的大气压不垮我瘦弱的身躯！“瞧，下面的风景多美！”，“你升腾的轨迹如慧尾扫过天际，快看看这瞬间的异彩”不！我不能回头，我不想留恋过程，是烟花便注定要绽放，我要用燃烧实现自身的价值，用炫丽耀眼的光芒诠释我的人生！也许有人要笑我是痴儿，不解荣枯事，也许绽放就意味着消亡，是！多少秦宫汉阙，都做了衰草牛羊野，纵荒坟，横断碑，不辩龙蛇。然！多少风流韵事，历经了历史风霜雪，涤浊评，竖口碑，长留人间！对于我，选择了便意味着义无反顾！

不再回头，我要在夜空中绽放，我将与黎明共舞！穷，气不短，达，志不改！', '你笑，全世界都在笑；

 你哭，就你一个人哭……', '2001-01-24 16:26:00', 3, '20021120163638_bbsid_88223_board_5_01cd94c36f.html', '20021120163638');
